<?php
declare(strict_types=1);namespace App\Services\ControlEscaneres\Auditoria;use App\Repositories\ControlEscaneres\Contracts\AuditRepositoryInterface;use App\Services\ControlEscaneres\Shared\BusinessClockInterface;use App\DTO\ControlEscaneres\{AuditEventData,AuthenticatedActorData,BusinessRequestContext};final class ScannerAuditService{public function __construct(private AuditRepositoryInterface$repo,private BusinessClockInterface$clock){}public function record(string$action,string$entity,?int$entityId,array$before,array$after,AuthenticatedActorData$actor,BusinessRequestContext$ctx,array$metadata=[]):int{return$this->repo->append(new AuditEventData($actor,$action,'control-escaneres',$entity,'exito',$this->clock->now(),$entityId,$before,$after,$metadata,$ctx->requestId,$ctx->sessionFingerprint,$ctx->ipAddress))->id;}}
